import React from "react";
import "./SocialMedia.scss";
import { socialMediaInfo } from "../../portfolio";

export default function SocialMedia() {
  if (!socialMediaInfo.display) {
    return null;
  }
  return (
    <div className="social-media-div">
      {socialMediaInfo.github ? (
        <a
          href={socialMediaInfo.github}
          className="icon-button github"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-brands fa-github"></i>
          <span></span>
        </a>
      ) : null}

      {socialMediaInfo.gitlab ? (
        <a
          href={socialMediaInfo.gitlab}
          className="icon-button gitlab"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-brands fa-square-gitlab"></i>
          <span></span>
        </a>
      ) : null}

      {socialMediaInfo.stackoverflow ? (
        <a
          href={socialMediaInfo.stackoverflow}
          className="icon-button stack-overflow"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-brands fa-stack-overflow"></i>
          <span></span>
        </a>
      ) : null}

      {socialMediaInfo.leetcode ? (
        <a
          href={socialMediaInfo.leetcode}
          className="icon-button leetcode"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-brands fa-leetcode"></i>
          <span></span>
        </a>
      ) : null}

      {socialMediaInfo.linkedin ? (
        <a
          href={socialMediaInfo.linkedin}
          className="icon-button linkedin"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-brands fa-square-linkedin"></i>
          <span></span>
        </a>
      ) : null}

      {socialMediaInfo.gmail ? (
        <a
          href={`mailto:${socialMediaInfo.gmail}`}
          className="icon-button google"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-solid fa-envelope"></i>
          <span></span>
        </a>
      ) : null}

      {socialMediaInfo.instagram ? (
        <a
          href={socialMediaInfo.instagram}
          className="icon-button instagram"
          target="_blank"
          rel="noopener noreferrer"
        >
          <i className="fa-brands fa-instagram"></i>
          <span></span>
        </a>
      ) : null}
    </div>
  );
}
