import React, { useContext } from "react";
import Headroom from "react-headroom";
import "./Header.scss";
import ToggleSwitch from "../toggleSwitch/ToggleSwitch";
import StyleContext from "../../contexts/StyleContext";
import {
  greetingInfo,
  skillInfo,
  educationInfo,
  experienceInfo,
  openSourceInfo,
  achievementInfo,
  blogInfo,
  talkInfo
} from "../../portfolio";

function Header() {
  const { isDark } = useContext(StyleContext);
  const viewSkill = skillInfo.display;
  const viewEducation = educationInfo.display;
  const viewExperience = experienceInfo.display;
  const viewOpenSource = openSourceInfo.display;
  const viewAchievement = achievementInfo.display;
  const viewBlog = blogInfo.display;
  const viewTalk = talkInfo.display;

  return (
    <Headroom>
      <header className={isDark ? "dark-menu header" : "header"}>
        <a href="/" className="logo">
          <span className="grey-color"> &lt;</span>
          <span className="logo-name">{greetingInfo.username}</span>
          <span className="grey-color">/&gt;</span>
        </a>
        <input className="menu-btn" type="checkbox" id="menu-btn" />
        <label
          className="menu-icon"
          htmlFor="menu-btn"
          style={{ color: "white" }}
        >
          <span className={isDark ? "navicon navicon-dark" : "navicon"}></span>
        </label>
        <ul className={isDark ? "dark-menu menu" : "menu"}>
          {viewSkill && (
            <li>
              <a href="#skill">Skills</a>
            </li>
          )}
          {viewEducation && (
            <li>
              <a href="#education">Education</a>
            </li>
          )}
          {viewExperience && (
            <li>
              <a href="#experience">Experiences</a>
            </li>
          )}
          {viewOpenSource && (
            <li>
              <a href="#opensource">Open Source</a>
            </li>
          )}
          {viewAchievement && (
            <li>
              <a href="#achievement">Achievements</a>
            </li>
          )}
          {viewBlog && (
            <li>
              <a href="#blog">Blogs</a>
            </li>
          )}
          {viewTalk && (
            <li>
              <a href="#talk">Talks</a>
            </li>
          )}
          <li>
            <a href="#contact">Contacts</a>
          </li>
          <li>
            {/* eslint-disable-next-line jsx-a11y/anchor-is-valid */}
            <a>
              <ToggleSwitch />
            </a>
          </li>
        </ul>
      </header>
    </Headroom>
  );
}
export default Header;
